1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	const PROCESSING_FEE = 5;
13	const FIRST_INSURANCE_RATE = 0.1;
14	
15	const BASE_PREMIUMS: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	  rune: 25,
21	};
22	
23	const RUNES_PER_BLOCK = 3;
24	const COMPONENT_BLOCK_BASE = 60;
25	
26	export function quote(_customer: Customer, items: Item[]): number {
27	  // Kept as `base + base * rate` (rather than `base * (1 + rate)`) so the
28	  // reducer accumulates base and insurance separately — avoids 25 * 1.1 + 25 * 1.1
29	  // producing 60.00000000000001 for the two-rune case.
30	  const baseSum = items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
31	  // A block of exactly RUNES_PER_BLOCK alike runes replaces their summed base with COMPONENT_BLOCK_BASE.
32	  const runeCount = items.filter((item) => item.type === "rune").length;
33	  const blockAdjustment = runeCount === RUNES_PER_BLOCK ? COMPONENT_BLOCK_BASE - RUNES_PER_BLOCK * BASE_PREMIUMS.rune : 0;
34	  const adjustedBase = baseSum + blockAdjustment;
35	  const firstInsurance = adjustedBase * FIRST_INSURANCE_RATE;
36	  return adjustedBase + firstInsurance + PROCESSING_FEE;
37	}
